default_config.nats:
# ================================== General ===================================
name: "winlogbeat-${node.ip}-${node.cloud_region}"
tags: ["bk-lite", "logstash", "windows"]

# ================================== Logging ===================================
logging.level: info
logging.to_files: true
logging.files:
  path: C:\fusion-collectors\log\winlogbeat
  name: winlogbeat
  keepfiles: 7
  permissions: 0600

# ================================== Outputs ===================================
output.logstash:
  hosts: ["localhost:15044"]
  worker: 1
  bulk_max_size: 2048
  timeout: 30s
  max_retries: -1

# ================================== Processors ===================================
processors:
  - add_host_metadata:
      when.not.contains.tags: forwarded

  - script:
      lang: javascript
      source: >
        function process(event) {
          var evt = event.Get();

          if (evt['@timestamp']) {
            event.Put('timestamp', evt['@timestamp']);
          }

          if (evt.winlog) {
            event.Put('event_id', evt.winlog.event_id || 0);
            event.Put('channel', evt.winlog.channel || 'unknown');
            event.Put('provider_name', evt.winlog.provider_name || 'unknown');
            event.Put('computer_name', evt.winlog.computer_name || 'unknown');
            event.Put('record_id', evt.winlog.record_id || 0);

            if (evt.winlog.event_data) {
              event.Put('event_data', evt.winlog.event_data);
            }

            if (evt.winlog.user) {
              event.Put('user_name', evt.winlog.user.name || 'unknown');
              event.Put('user_domain', evt.winlog.user.domain || 'unknown');
              event.Put('user_type', evt.winlog.user.type || 'unknown');
            }
          }

          if (evt.log && evt.log.level) {
            event.Put('level', evt.log.level);
          }

          if (evt.message) {
            event.Put('_msg', evt.message);
          }
        }

# ================================== Event Logs ===================================
winlogbeat.event_logs:
